import{_ as t,c as a,o,a5 as i}from"./chunks/framework.CgT1UzWm.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/index.md","filePath":"guide/changelog/index.md"}'),d={name:"guide/changelog/index.md"};function r(l,e,n,s,c,h){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Select a version below to view the full changelog.</p><p>Note: The changelog for versions older than 3.0 can be found here: <a href="https://github.com/NpgsqlRest/NpgsqlRest/blob/master/changelog-old.md" target="_blank" rel="noreferrer">Changelog Archive</a></p><hr><h2 id="version-3-18-latest" tabindex="-1">Version 3.18 (Latest) <a class="header-anchor" href="#version-3-18-latest" aria-label="Permalink to &quot;Version 3.18 (Latest)&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.18.2.html">v3.18.2</a></td><td>2026-06-26</td></tr><tr><td><a href="/guide/changelog/v3.18.1.html">v3.18.1</a></td><td>2026-06-23</td></tr><tr><td><a href="/guide/changelog/v3.18.0.html">v3.18.0</a></td><td>2026-06-23</td></tr></tbody></table></div></div><ul><li>New: <code>ProxyOptions.MaxForwardedQueryParamLength</code> (default <code>2048</code>) — a server-filled value too long for the proxy query string is skipped with a warning instead of producing an unusable request line (HTTP 414/431); forward large values via a body-carrying method and <code>@body_parameter_name</code></li><li>New: <code>OmitAutomaticParameters</code> on the TypeScript client, HTTP file, and OpenAPI generators (default <code>false</code>) — omit optional server-filled parameters (HTTP Custom Type fields, resolved-parameter expressions, upload metadata, IP/claim params) from generated request shapes</li><li>Fix: <code>@body_parameter_name</code> now matches an HTTP Custom Type field by its converted, actual, or expanded signature name, case-insensitively — applied consistently by request handling and all code generators (also fixes the HTTP file and OpenAPI generators leaving the field in the query string)</li><li>Fix: TypeScript client generation for <code>@body_parameter_name</code> endpoints — no leaked <code>?</code> in the body property name, the body parameter is excluded from the query string, and no <code>fetch</code> body is emitted for <code>GET</code></li><li>Fix: all automatic (server-filled) proxy parameters — user claims, IP, HTTP Custom Type fields, and resolved-parameter expressions — now forward to proxy endpoints uniformly, with placement following the endpoint&#39;s <code>RequestParamType</code> (query string or merged into the JSON body) rather than the HTTP verb</li><li>New: HTTP Custom Type response caching via the <code>@cache</code> directive — opt-in, GET-only outbound response caching with TTL, success-only storage, and stampede protection; configured globally under <code>HttpClientOptions</code> (<code>CacheEnabled</code>, <code>MaxCacheEntries</code>, <code>CachePruneIntervalSeconds</code>)</li><li>Fix: an HTTP Custom Type parameter on a database-function endpoint fired one outbound call per composite field (a 6-field type → 6 identical calls); now one call per distinct type, shared from a single response</li><li>Fix: <code>@timeout</code>, <code>@retry_delay</code>, and <code>@cache</code> directives placed after the headers (as the docs showed) were silently ignored — both before-request-line and after-headers placements are now equivalent</li></ul><hr><h2 id="version-3-17" tabindex="-1">Version 3.17 <a class="header-anchor" href="#version-3-17" aria-label="Permalink to &quot;Version 3.17&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.17.0.html">v3.17.0</a></td><td>2026-06-10</td></tr></tbody></table></div></div><ul><li>New plugin <code>NpgsqlRest.Mcp</code> — expose opted-in PostgreSQL routines as MCP tools (<code>tools/list</code> / <code>tools/call</code> over Streamable HTTP) via the <code>@mcp</code> annotation; a bare <code>@mcp</code> with no HTTP tag is an MCP-only tool with no public route</li><li>MCP OAuth 2.1 resource-server authorization: Protected Resource Metadata (RFC 9728), audience binding (RFC 8707), per-tool <code>@authorize</code> enforcement on <code>tools/call</code></li><li>Neutral plugin extension points on <code>RoutineEndpoint</code> (<code>HandleCommentLine</code>, <code>Items</code>, <code>UnhandledCommentLines</code>) and new <code>CommentsMode.OnlyAnnotated</code> (now the client default)</li><li>New: <code>{name}</code> annotation substitution can resolve allowlisted environment variables (<code>NpgsqlRest:AvailableEnvVars</code>); matching is now case-insensitive, unknown placeholders log a build-time warning</li><li>New: optional <code>{NAME}</code> and required <code>{!NAME}</code> environment-variable placeholders in config values — missing optional variables no longer crash typed reads</li><li>Breaking: safer configuration defaults — <code>Cors:AllowCredentials</code> is now <code>false</code>, passkey <code>UserVerificationRequirement</code> / <code>ResidentKeyRequirement</code> default to <code>&quot;required&quot;</code>, <code>TestConnectionStrings</code> defaults to <code>true</code></li><li>Breaking (C# API only): <code>RoutineEndpoint.OpenApiHide</code> / <code>OpenApiTags</code> removed — the OpenAPI plugin parses the <code>@openapi</code> annotation itself; annotation users are unaffected</li><li>🔴 Security fix: SSE per-event <code>USING HINT</code> scopes were not enforced — hint-scoped events were delivered to every subscriber; upgrade strongly recommended for hint-based SSE scoping</li><li>Fix: bare <code>@cached</code> (no parameter list) keyed only on the routine name, serving the first cached response to all inputs</li><li>Fix: HybridCache silently bypassed the cache on null cached parameters (<code>Cache key contains invalid content</code>)</li><li>Fix: malformed JSON request body now returns <code>400 Bad Request</code> (was <code>404</code>)</li><li>Fix: JSON command parameters accept <code>json</code>, <code>jsonb</code>, or <code>text</code> target types</li></ul><hr><h2 id="version-3-16" tabindex="-1">Version 3.16 <a class="header-anchor" href="#version-3-16" aria-label="Permalink to &quot;Version 3.16&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.16.3.html">v3.16.3</a></td><td>2026-06-03</td></tr><tr><td><a href="/guide/changelog/v3.16.2.html">v3.16.2</a></td><td>2026-06-02</td></tr><tr><td><a href="/guide/changelog/v3.16.1.html">v3.16.1</a></td><td>2026-06-01</td></tr><tr><td><a href="/guide/changelog/v3.16.0.html">v3.16.0</a></td><td>2026-05-20</td></tr></tbody></table></div></div><ul><li><p>New: <code>AvailableEnvVars</code> under <code>StaticFiles:ParseContentOptions</code> templates environment-variable values into served static content (same <code>{NAME}</code> tags as claims) — build a SPA bundle once, inject per-environment values from pod env vars at boot</p></li><li><p>New: rate-limiter rejection <code>StatusCode</code>/<code>StatusMessage</code> are now overridable per policy (the global values stay as defaults); ships a ready-to-use disabled <code>login_throttle</code> policy</p></li><li><p>Fix: cache stampede protection now actually fires for cached routine responses (<code>IRoutineCache.GetOrCreateAsync</code>); a burst of identical cold-cache requests collapses to a single database execution</p></li><li><p>Fix: JSON-to-parameter parsers for <code>timestamp</code>, <code>timestamptz</code>, <code>time</code>, and <code>timetz</code> are now host-TZ-independent (silent host-offset shift removed)</p></li><li><p>Fix: <code>TryParseDate</code> falls back to a <code>DateTime</code> parse when <code>DateOnly</code> rejects offset/<code>Z</code>-bearing inputs</p></li><li><p>Breaking: JSON timestamps are now interpreted as UTC by default (naive ISO strings assumed UTC, <code>Z</code> / offset-bearing strings converted to UTC)</p></li><li><p>New <code>NpgsqlRest:JsonTimestampsAreUtc</code> config key — opt-out escape hatch to restore the pre-3.16.0 host-local interpretation</p></li></ul><hr><h2 id="version-3-15" tabindex="-1">Version 3.15 <a class="header-anchor" href="#version-3-15" aria-label="Permalink to &quot;Version 3.15&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.15.2.html">v3.15.2</a></td><td>2026-05-11</td></tr><tr><td><a href="/guide/changelog/v3.15.1.html">v3.15.1</a></td><td>2026-05-11</td></tr><tr><td><a href="/guide/changelog/v3.15.0.html">v3.15.0</a></td><td>2026-05-11</td></tr></tbody></table></div></div><ul><li>Auth: named cookie schemes now actually authenticate requests (cookie-aware policy-scheme dispatch)</li><li>New <code>Auth:CookieSameSite</code> and <code>Auth:CookieSecure</code> config keys for cross-origin SPA / mobile clients (root + per-scheme)</li><li>OpenAPI filtering: <code>IncludeSchemas</code>, <code>ExcludeSchemas</code>, <code>NameSimilarTo</code>, <code>NameNotSimilarTo</code>, <code>RequiresAuthorizationOnly</code></li><li>New <code>@openapi</code> annotation — <code>@openapi hide</code> and <code>@openapi tag &lt;name&gt;</code> for per-routine OpenAPI control</li><li>Fix: <code>Auth:Schemes</code> keys validated by <code>Type</code>, not by name — custom schemes named like the docs examples no longer fail startup (3.15.1)</li><li>Fix: <code>--config</code> and <code>--validate</code> CLI commands honor <code>ValidateConfigKeys</code> mode (3.15.1)</li><li>Fix: <code>RateLimiterOptions:Policies</code> and <code>CacheOptions:Profiles</code> validate by shape — custom policy / profile names no longer fail startup under <code>ValidateConfigKeys: &quot;Error&quot;</code> (3.15.2)</li><li>Improvement: <code>ValidationOptions:Rules</code> rule bodies validated for typos (3.15.2)</li></ul><hr><h2 id="version-3-14" tabindex="-1">Version 3.14 <a class="header-anchor" href="#version-3-14" aria-label="Permalink to &quot;Version 3.14&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.14.0.html">v3.14.0</a></td><td>2026-05-09</td></tr></tbody></table></div></div><ul><li>Standalone client no longer wires the <code>NpgsqlRest.CrudSource</code> plugin (library use unchanged)</li><li>New SSE annotations <code>@sse_publish</code> and <code>@sse_subscribe</code> — split publisher and subscriber roles</li><li>Warning when a <code>RAISE</code> looks like a missed <code>@sse_publish</code></li><li>Reliable SSE connection handshake</li><li>Startup error when claim-mapped parameters use a non-text type</li><li>Warning when a request value is overridden by claim auto-bind</li><li>Lower-allocation JSON conversion for arrays and composites</li><li>Hardening: <code>ArrayPool</code> rentals released in <code>try/finally</code>, column-decryption failures logged at Trace</li></ul><hr><h2 id="version-3-13" tabindex="-1">Version 3.13 <a class="header-anchor" href="#version-3-13" aria-label="Permalink to &quot;Version 3.13&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.13.0.html">v3.13.0</a></td><td>2026-04-24</td></tr></tbody></table></div></div><ul><li>Auth Schemes — named additional authentication schemes (Cookies / BearerToken / Jwt)</li><li>Login functions can select a scheme via the <code>scheme</code> column</li></ul><hr><h2 id="version-3-12" tabindex="-1">Version 3.12 <a class="header-anchor" href="#version-3-12" aria-label="Permalink to &quot;Version 3.12&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.12.0.html">v3.12.0</a></td><td>2026-03-23</td></tr></tbody></table></div></div><ul><li>New endpoint source plugin: <code>NpgsqlRest.SqlFileSource</code> — generate REST API endpoints directly from <code>.sql</code> files</li><li>Multi-command SQL files with batched execution and named result sets</li><li>New <code>@param</code> / <code>@parameter</code> annotation for renaming and retyping parameters across all endpoint types</li><li>Glob pattern <code>**</code> recursive matching support</li><li>Interface refactoring: <code>IEndpointSource</code> / <code>IRoutineSource</code> split</li><li>TsClient: multi-command SQL file endpoint support</li><li>Composite type cache public API</li></ul><hr><h2 id="version-3-11" tabindex="-1">Version 3.11 <a class="header-anchor" href="#version-3-11" aria-label="Permalink to &quot;Version 3.11&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.11.1.html">v3.11.1</a></td><td>2026-03-13</td></tr><tr><td><a href="/guide/changelog/v3.11.0.html">v3.11.0</a></td><td>2026-03-10</td></tr></tbody></table></div></div><ul><li><code>proxy_out</code> annotation (post-execution proxy)</li><li>TsClient: <code>proxy</code> and <code>proxy_out</code> passthrough endpoint support</li><li><code>authorize</code> annotation now matches user ID and user name claims</li></ul><hr><h2 id="version-3-10" tabindex="-1">Version 3.10 <a class="header-anchor" href="#version-3-10" aria-label="Permalink to &quot;Version 3.10&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.10.0.html">v3.10.0</a></td><td>2026-02-25</td></tr></tbody></table></div></div><ul><li>Resolved parameter expressions for server-side secret handling</li><li>HTTP Client Type retry logic (<code>@retry_delay</code>)</li><li>Data Protection encrypt/decrypt annotations</li></ul><hr><h2 id="version-3-9" tabindex="-1">Version 3.9 <a class="header-anchor" href="#version-3-9" aria-label="Permalink to &quot;Version 3.9&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.9.0.html">v3.9.0</a></td><td>2026-02-23</td></tr></tbody></table></div></div><ul><li>Commented configuration output (<code>--config</code>)</li><li>Configuration search and filter (<code>--config [filter]</code>)</li><li>CLI improvements and test suite</li></ul><hr><h2 id="version-3-8" tabindex="-1">Version 3.8 <a class="header-anchor" href="#version-3-8" aria-label="Permalink to &quot;Version 3.8&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.8.0.html">v3.8.0</a></td><td>2025-02-11</td></tr></tbody></table></div></div><ul><li>Configuration key validation</li><li>Optional path parameters</li><li>Machine-readable CLI commands for tool integration</li><li>Universal <code>fallback_handler</code> for all upload handlers</li></ul><hr><h2 id="version-3-7" tabindex="-1">Version 3.7 <a class="header-anchor" href="#version-3-7" aria-label="Permalink to &quot;Version 3.7&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.7.0.html">v3.7.0</a></td><td>2025-02-07</td></tr></tbody></table></div></div><ul><li>Pluggable table format renderers (HTML, Excel)</li><li>TsClient per-endpoint URL export control</li><li>Excel upload handler <code>fallback_handler</code></li></ul><hr><h2 id="version-3-6" tabindex="-1">Version 3.6 <a class="header-anchor" href="#version-3-6" aria-label="Permalink to &quot;Version 3.6&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.6.3.html">v3.6.3</a></td><td>2025-02-03</td></tr><tr><td><a href="/guide/changelog/v3.6.2.html">v3.6.2</a></td><td>2025-02-02</td></tr><tr><td><a href="/guide/changelog/v3.6.1.html">v3.6.1</a></td><td>2025-02-02</td></tr><tr><td><a href="/guide/changelog/v3.6.0.html">v3.6.0</a></td><td>2025-02-01</td></tr></tbody></table></div></div><ul><li>Security headers middleware</li><li>Forwarded headers middleware</li><li>Health check endpoints</li><li>PostgreSQL statistics endpoints</li></ul><hr><h2 id="version-3-5" tabindex="-1">Version 3.5 <a class="header-anchor" href="#version-3-5" aria-label="Permalink to &quot;Version 3.5&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.5.0.html">v3.5.0</a></td><td>2025-01-28</td></tr></tbody></table></div></div><ul><li>PasskeyAuth (WebAuthn/FIDO2)</li><li>Response compression fix for static files</li><li>Separate core and client logging</li></ul><hr><h2 id="version-3-4" tabindex="-1">Version 3.4 <a class="header-anchor" href="#version-3-4" aria-label="Permalink to &quot;Version 3.4&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.4.8.html">v3.4.8</a></td><td>2025-01-26</td></tr><tr><td><a href="/guide/changelog/v3.4.7.html">v3.4.7</a></td><td>2025-01-21</td></tr><tr><td><a href="/guide/changelog/v3.4.6.html">v3.4.6</a></td><td>2025-01-21</td></tr><tr><td><a href="/guide/changelog/v3.4.5.html">v3.4.5</a></td><td>2025-01-19</td></tr><tr><td><a href="/guide/changelog/v3.4.4.html">v3.4.4</a></td><td>2025-01-17</td></tr><tr><td><a href="/guide/changelog/v3.4.3.html">v3.4.3</a></td><td>2025-01-16</td></tr><tr><td><a href="/guide/changelog/v3.4.2.html">v3.4.2</a></td><td>2025-01-15</td></tr><tr><td><a href="/guide/changelog/v3.4.1.html">v3.4.1</a></td><td>2025-01-15</td></tr><tr><td><a href="/guide/changelog/v3.4.0.html">v3.4.0</a></td><td>2025-01-16</td></tr></tbody></table></div></div><ul><li>Composite type support (arrays, nested JSON)</li><li>Deep nested composite type resolution</li><li>Multidimensional array support</li><li>Performance optimizations (type category lookup, StringBuilder pooling, CancellationToken propagation)</li></ul><hr><h2 id="version-3-3" tabindex="-1">Version 3.3 <a class="header-anchor" href="#version-3-3" aria-label="Permalink to &quot;Version 3.3&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.3.1.html">v3.3.1</a></td><td>2025-01-14</td></tr><tr><td><a href="/guide/changelog/v3.3.0.html">v3.3.0</a></td><td>2025-01-08</td></tr></tbody></table></div></div><ul><li>Parameter validation</li><li>Linux ARM64 build and Docker image</li><li>Proxy response caching</li><li>Optional <code>@</code> prefix for comment annotations</li></ul><hr><h2 id="version-3-2" tabindex="-1">Version 3.2 <a class="header-anchor" href="#version-3-2" aria-label="Permalink to &quot;Version 3.2&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.2.7.html">v3.2.7</a></td><td>2025-01-05</td></tr><tr><td><a href="/guide/changelog/v3.2.6.html">v3.2.6</a></td><td>2025-01-04</td></tr><tr><td><a href="/guide/changelog/v3.2.4.html">v3.2.4</a></td><td>2025-01-03</td></tr><tr><td><a href="/guide/changelog/v3.2.3.html">v3.2.3</a></td><td>2025-12-30</td></tr><tr><td><a href="/guide/changelog/v3.2.2.html">v3.2.2</a></td><td>2025-12-24</td></tr><tr><td><a href="/guide/changelog/v3.2.1.html">v3.2.1</a></td><td>2025-12-23</td></tr><tr><td><a href="/guide/changelog/v3.2.0.html">v3.2.0</a></td><td>2025-12-22</td></tr></tbody></table></div></div><ul><li>Reverse proxy feature</li><li>JWT authentication support</li><li>HybridCache support</li><li>Docker image with Bun runtime</li></ul><hr><h2 id="version-3-1" tabindex="-1">Version 3.1 <a class="header-anchor" href="#version-3-1" aria-label="Permalink to &quot;Version 3.1&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.1.3.html">v3.1.3</a></td><td>2025-12-21</td></tr><tr><td><a href="/guide/changelog/v3.1.2.html">v3.1.2</a></td><td>2025-12-20</td></tr><tr><td><a href="/guide/changelog/v3.1.1.html">v3.1.1</a></td><td>2025-12-15</td></tr><tr><td><a href="/guide/changelog/v3.1.0.html">v3.1.0</a></td><td>2025-12-13</td></tr></tbody></table></div></div><ul><li>HTTP Types (external API calls from PostgreSQL functions)</li><li>Path parameters support</li><li>SIMD-accelerated string processing</li><li>Routine caching improvements</li><li>Multi-host connection support</li></ul><hr><h2 id="version-3-0" tabindex="-1">Version 3.0 <a class="header-anchor" href="#version-3-0" aria-label="Permalink to &quot;Version 3.0&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Version</th><th>Date</th></tr></thead><tbody><tr><td><a href="/guide/changelog/v3.0.1.html">v3.0.1</a></td><td>2025-11-28</td></tr><tr><td><a href="/guide/changelog/v3.0.0.html">v3.0.0</a></td><td>2025-11-27</td></tr></tbody></table></div></div><ul><li>.NET 10 target framework</li><li>Rate limiter</li><li>OpenAPI 3.0 support</li><li>Error handling improvements (RFC 7807 Problem Details)</li><li>TsClient improvements</li><li>SSE (Server-Sent Events) naming refactor</li></ul>',79)]))}const g=t(d,[["render",r]]);export{p as __pageData,g as default};
